function initMobileMenu(){const e=document.querySelector(".menu-toggle"),t=document.querySelector(".mobile-nav");e&&t&&(e.addEventListener("click",()=>{const n="true"===e.getAttribute("aria-expanded");e.setAttribute("aria-expanded",!n),t.classList.toggle("open"),document.body.classList.toggle("menu-open")}),t.querySelectorAll("a").forEach(n=>{n.addEventListener("click",()=>{e.setAttribute("aria-expanded","false"),t.classList.remove("open"),document.body.classList.remove("menu-open")})}))}function initGalleryCarousels(){document.querySelectorAll("[data-carousel]").forEach(e=>{const t=e.querySelectorAll(".carousel-slide"),n=e.querySelector(".carousel-btn.prev"),o=e.querySelector(".carousel-btn.next"),r=e.querySelector(".carousel-counter");let l=0;function c(){t.forEach((e,t)=>{e.classList.toggle("active",t===l)}),r&&(r.textContent=`Item ${l+1} of ${t.length}`)}n&&n.addEventListener("click",()=>{l=(l-1+t.length)%t.length,c()}),o&&o.addEventListener("click",()=>{l=(l+1)%t.length,c()})})}function initReviewsCarousel(){const e=document.querySelector("[data-reviews]");if(!e)return;const t=e.querySelectorAll("[data-review]"),n=e.querySelectorAll(".dot"),o=e.querySelector(".carousel-btn.prev"),r=e.querySelector(".carousel-btn.next");let l=0;function c(e){l=(e+t.length)%t.length,t.forEach((e,t)=>e.classList.toggle("active",t===l)),n.forEach((e,t)=>e.classList.toggle("active",t===l))}o&&o.addEventListener("click",()=>c(l-1)),r&&r.addEventListener("click",()=>c(l+1)),n.forEach(e=>{e.addEventListener("click",()=>{c(parseInt(e.dataset.index,10))})})}function initSmoothScrollNav(){document.querySelectorAll('a[href^="#"]').forEach(e=>{e.addEventListener("click",t=>{const n=document.querySelector(e.getAttribute("href"));n&&(t.preventDefault(),n.scrollIntoView({behavior:"smooth"}))})})}document.addEventListener("DOMContentLoaded",()=>{initMobileMenu(),initGalleryCarousels(),initReviewsCarousel(),initSmoothScrollNav()});